const leads = $input.all();

const scoredLeads = leads.map(item => {
  const data = item.json;
  let score = 0;
  let scoreBreakdown = {};

  // VOLUME SCORE (0-10 points)
  const reviewCount = data.review_count || 0;
  if (reviewCount >= 1000) {
    score += 10;
    scoreBreakdown.volume = '10 (1000+ reviews - Stadium/Arena)';
  } else if (reviewCount >= 500) {
    score += 8;
    scoreBreakdown.volume = '8 (500-999 reviews - High volume)';
  } else if (reviewCount >= 200) {
    score += 5;
    scoreBreakdown.volume = '5 (200-499 reviews - Mid tier)';
  } else if (reviewCount >= 50) {
    score += 3;
    scoreBreakdown.volume = '3 (50-199 reviews - Small)';
  } else {
    score += 1;
    scoreBreakdown.volume = '1 (<50 reviews - Very small)';
  }

  // PAIN SIGNALS (0-5 points)
  const painSignals = (data.pain_signals || '').toLowerCase();
  let painScore = 0;
  if (painSignals.includes('long wait')) painScore += 2;
  if (painSignals.includes('long line')) painScore += 2;
  if (painSignals.includes('slow service')) painScore += 1;
  if (painSignals.includes('crowded')) painScore += 1;
  painScore = Math.min(painScore, 5);
  score += painScore;
  scoreBreakdown.pain = `${painScore} (Pain signals detected)`;

  // RATING QUALITY (0-3 points)
  const rating = data.rating || 0;
  if (rating >= 4.0) {
    score += 3;
    scoreBreakdown.rating = '3 (4.0+ rating - Quality venue)';
  } else if (rating >= 3.5) {
    score += 2;
    scoreBreakdown.rating = '2 (3.5-3.9 rating)';
  } else if (rating >= 3.0) {
    score += 1;
    scoreBreakdown.rating = '1 (3.0-3.4 rating)';
  }

  // TECH READINESS (0-3 points)
  const website = (data.website || '').toLowerCase();
  let techScore = 0;
  if (website.includes('order') || website.includes('menu')) techScore += 1;
  if (data.pos_system && data.pos_system !== '') techScore += 2;
  score += techScore;
  scoreBreakdown.tech = `${techScore} (Tech indicators)`;

  // MULTI-LOCATION MULTIPLIER
  const locationCount = data.location_count || 1;
  if (locationCount >= 3) {
    score = Math.floor(score * 1.5);
    scoreBreakdown.multiplier = '1.5x (Multi-location)';
  }

  // ESTIMATED MONTHLY REVENUE LOSS
  // Formula: (review_count / 30) * (pain_score / 5) * $200 avg_order * 25% abandonment
  const avgDailyGuests = reviewCount / 30; // Rough proxy
  const abandonmentRate = 0.25;
  const avgOrder = 200;
  const estimatedLoss = Math.round(
    avgDailyGuests * (painScore / 5) * avgOrder * abandonmentRate * 30
  );

  // DETERMINE STATUS
  let status;
  if (score >= 15) {
    status = 'Hot Lead - Prioritize';
  } else if (score >= 10) {
    status = 'Qualified - Standard Outreach';
  } else if (score >= 5) {
    status = 'Low Priority - Nurture';
  } else {
    status = 'Disqualify';
  }

  return {
    ...data,
    score: score,
    estimated_monthly_loss: estimatedLoss,
    status: status,
    last_activity: new Date().toISOString()
  };
});

return scoredLeads;

